import { GearSetType, GearCategory } from "../../consts/enums";
import { GearRank } from "../../consts/types";
import { Gear } from "./gear";

/**
 * Generic gear stub for registry entries that don't have full stat tables yet.
 */
export class GenericGear extends Gear {
  constructor(params: {
    gearCategory: GearCategory;
    gearSetType?: GearSetType;
    rank?: GearRank;
  }) {
    super({
      gearCategory: params.gearCategory,
      gearSetType: params.gearSetType ?? GearSetType.NONE,
      rank: params.rank ?? 1,
      allLevels: { 1: {}, 2: {}, 3: {}, 4: {} },
    });
  }
}
