// ── Frame modifier hooks (operator-specific behaviors) ──────────────────────

/** Dolly Rush susceptibility: per-level bonus (Physical + Arts). */
const DOLLY_RUSH_SUSCEPTIBILITY = [
  0.12, 0.12, 0.12, 0.13, 0.13, 0.13, 0.14, 0.14, 0.16, 0.17, 0.18, 0.2,
] as const;

/** Dolly Rush susceptibility duration in frames (30s at 120fps). */
const DOLLY_RUSH_DURATION_FRAMES = 3600;

/** Focus susceptibility: per-level bonus (all elements). */
const FOCUS_SUSCEPTIBILITY = [
  0.05, 0.05, 0.06, 0.06, 0.07, 0.07, 0.08, 0.08, 0.08, 0.09, 0.09, 0.10,
] as const;

/** Focus duration in frames (60s at 120fps). */
const FOCUS_DURATION_FRAMES = 7200;

const FRAME_MODIFIERS: Record<string, FrameModifierFn> = {
  ardelia: (_frame, index, skillCategory): FrameExtras | undefined => {
    const extras: FrameExtras = { damageElement: ElementType.NATURE };
    // Dolly Rush (battle skill): first tick consumes Corrosion → apply Susceptibility
    if (skillCategory === 'BATTLE_SKILL' && index === 0) {
      const consumeReaction: FrameReactionConsumption = {
        columnId: 'corrosion',
        applyStatus: {
          target: TargetType.ENEMY,
          status: StatusType.SUSCEPTIBILITY,
          stacks: 1,
          durationFrames: DOLLY_RUSH_DURATION_FRAMES,
          susceptibility: {
            [ElementType.PHYSICAL]: DOLLY_RUSH_SUSCEPTIBILITY,
            [ElementType.HEAT]: DOLLY_RUSH_SUSCEPTIBILITY,
            [ElementType.ELECTRIC]: DOLLY_RUSH_SUSCEPTIBILITY,
            [ElementType.CRYO]: DOLLY_RUSH_SUSCEPTIBILITY,
            [ElementType.NATURE]: DOLLY_RUSH_SUSCEPTIBILITY,
          },
          eventName: 'Dolly Rush',
        },
      };
      extras.consumeReaction = consumeReaction;
    }
    return extras;
  },

  antal: (_frame, index, skillCategory): FrameExtras | undefined => {
    // Focus (battle skill): first tick applies Focus susceptibility
    if (skillCategory === 'BATTLE_SKILL' && index === 0) {
      // Note: the DataDrivenSkillEventFrame won't produce applyStatus from JSON
      // because there's no statusInteraction for it. We override via consumeReaction
      // pattern — but Focus is applied via FrameApplyStatus, not consumeReaction.
      // We'll handle this by adding the status to the JSON data directly.
      return undefined;
    }
    // Combo skill: all frames duplicate the source infliction
    if (skillCategory === 'COMBO_SKILL') {
      return { duplicatesSourceInfliction: true };
    }
    return undefined;
  },
};

// ── Public API ──────────────────────────────────────────────────────────────

/** Sequence cache keyed by `operatorId:skillCategory`. */
const sequenceCache = new Map<string, readonly DataDrivenSkillEventSequence[]>();

/** Get the raw operator JSON for a given operator ID. */
export function getOperatorJson(operatorId: string): Record<string, any> | undefined {
  return OPERATOR_JSON[operatorId];
}

/** Get frame sequences for a skill category, with caching. */
export function getFrameSequences(
  operatorId: string,
  skillCategory: string,
): readonly DataDrivenSkillEventSequence[] {
  const cacheKey = `${operatorId}:${skillCategory}`;
  const cached = sequenceCache.get(cacheKey);
  if (cached) return cached;

  const json = OPERATOR_JSON[operatorId];
  if (!json) return [];

  const modifier = FRAME_MODIFIERS[operatorId];
  const sequences = buildSequencesFromOperatorJson(json, skillCategory, modifier);
  sequenceCache.set(cacheKey, sequences);
  return sequences;
}

/**
 * Get segment labels for a multi-sequence skill category.
 * Returns undefined for single-sequence skills.
 */
export function getSegmentLabels(
  operatorId: string,
  skillCategory: string,
): string[] | undefined {
  const sequences = getFrameSequences(operatorId, skillCategory);
  if (sequences.length <= 1) return undefined;

  const labels = sequences
    .map(seq => seq.segmentName)
    .filter((name): name is string => name != null);

  // If segments have names, use them; otherwise return undefined (basic attack uses index labels)
  return labels.length === sequences.length ? labels : undefined;
}

